def _gate_release_summary(results, tracker):
    savings_values = [float(r.get("savings_pct", 0.0)) for r in results]
    pressure_values = [float(r.get("pressure", 0.0)) for r in results]
    fallback_rows = [
        r for r in results
        if int(r.get("behavior_signals", {}).get("fail_open_compat_response", 0)) > 0
    ]
    return {
        "avg_savings_pct": round(sum(savings_values) / len(savings_values), 1),
        "avg_invisible_pressure": round(sum(pressure_values) / len(pressure_values), 1),
    }

def _export_gate_results(export, results, release_summary):
    export.write_text(json.dumps({
        "results": results,
        "release_summary": release_summary,
    }, indent=2))

